"use client";

import { useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { useParams } from "next/navigation";

import { getFreshness, getTeamBySlug, getTeamTrends } from "../../../lib/api";
import StatCard from "../../../components/StatCard";
import TeamTrendChart from "../../../components/TeamTrendChart";
import Badge from "../../../components/ui/badge";

export default function TeamDetailPage() {
  const params = useParams<{ slug: string }>();
  const slug = params?.slug;

  const teamQuery = useQuery({
    queryKey: ["team", slug],
    queryFn: () => getTeamBySlug(slug as string),
    enabled: !!slug
  });

  const teamId = useMemo(() => teamQuery.data?.id, [teamQuery.data?.id]);

  const trendsQuery = useQuery({
    queryKey: ["team-trends", teamId],
    queryFn: () => getTeamTrends(teamId as number, 5),
    enabled: !!teamId
  });

  const freshnessQuery = useQuery({
    queryKey: ["freshness"],
    queryFn: getFreshness
  });

  if (teamQuery.isLoading) {
    return <p className="text-slate">Loading team dashboard...</p>;
  }

  if (teamQuery.error || !teamQuery.data) {
    return <p className="text-red-500">Team not found.</p>;
  }

  const team = teamQuery.data;
  const agg = team.aggregates;

  return (
    <section className="grid gap-6">
      <div className="flex items-center justify-between">
        <p className="text-xs uppercase tracking-[0.3em] text-slate">Team Dashboard</p>
        {freshnessQuery.data?.last_import ? (
          <Badge variant="outline">
            Updated {new Date(freshnessQuery.data.last_import).toLocaleDateString()}
          </Badge>
        ) : (
          <Badge variant="outline">No refresh data</Badge>
        )}
      </div>
      <h2 className="text-3xl font-semibold -mt-2">{team.name}</h2>

      <div className="grid gap-4 md:grid-cols-3">
        <StatCard label="Goals / Match" value={agg.goals_per_match.toFixed(2)} />
        <StatCard label="Shooting" value={(agg.shooting_pct * 100).toFixed(1)} suffix="%" />
        <StatCard label="Extra-man" value={(agg.extra_man_pct * 100).toFixed(1)} suffix="%" />
        <StatCard label="Center" value={(agg.center_pct * 100).toFixed(1)} suffix="%" />
        <StatCard label="Sprints Won" value={(agg.sprints_win_pct * 100).toFixed(1)} suffix="%" />
        <StatCard label="Turnovers" value={agg.turnovers_per_match.toFixed(2)} suffix="/ match" />
      </div>

      {trendsQuery.data ? (
        <TeamTrendChart points={trendsQuery.data.points} />
      ) : (
        <div className="rounded-2xl bg-white/80 p-4 border border-white">
          <p className="text-slate">Trend data unavailable.</p>
        </div>
      )}
    </section>
  );
}
